import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[^a-zA-Z0-9]', password):
        return False
    common_passwords = {'password', '123456', 'admin', '123456789', 'qwerty', 'letmein', '123123', '000000'}
    if password in common_passwords:
        return False
    return True

